#!/usr/bin/env node
/**
 * Theme Drift Detector — A2 guardrails.
 *
 * Assertions (exit non-zero on any failure):
 *   1. themes/engine.js is NOT referenced from manifest.json content_scripts.
 *      The engine must never ship on SF tabs again.
 *   2. background.js does NOT contain engine markers (generateThemeCSS,
 *      _FONT_STACKS, resolveCustomTheme). Confirms the inlined block
 *      was removed and didn't sneak back via a copy-paste.
 *   3. Every preset CSS at content/themes/*.css has the AUTOGENERATED
 *      header stamp from scripts/render-presets.mjs. If anyone hand-edits
 *      a file and strips the header, this catches it.
 *   4. core/favicon/engine.js's ICONS array matches themes/engine.js's
 *      FAVICON_ICONS (ssoT). core/favicon/engine.js is a content-script
 *      runtime mirror — it must stay aligned with the canonical engine.
 *
 * Run: node scripts/check-theme-drift.js
 */

'use strict';

const fs = require('fs');
const path = require('path');

const REPO = path.resolve(__dirname, '..');

function readFile(rel) {
  return fs.readFileSync(path.join(REPO, rel), 'utf8');
}

function run() {
  const violations = [];

  // 1. Manifest must not reference themes/engine.js in content_scripts.
  try {
    const manifest = JSON.parse(readFile('manifest.json'));
    const cs = manifest.content_scripts || [];
    const flat = cs.flatMap(entry => entry.js || []);
    const offending = flat.filter(js => /themes\/(engine|derive|color-utils)\.js$/.test(js));
    if (offending.length) {
      violations.push({
        assertion: 'manifest:content_scripts',
        reason: `Theme engine files must not load on SF tabs. Found in content_scripts: ${offending.join(', ')}`,
      });
    }
  } catch (err) {
    violations.push({ assertion: 'manifest:parse', reason: `Failed to parse manifest.json: ${err.message}` });
  }

  // 2. background.js must not contain engine markers.
  const bg = readFile('background.js');
  const bgForbidden = [
    /function\s+generateThemeCSS\b/,
    /const\s+_FONT_STACKS\s*=/,
    /function\s+resolveCustomTheme\b/,
    /function\s+deriveFullTheme\b/,
    /function\s+_generateTypographyCSS\b/,
  ];
  for (const re of bgForbidden) {
    if (re.test(bg)) {
      violations.push({
        assertion: 'background.js:no-engine',
        reason: `Engine marker re-appeared in background.js: ${re}. Migration A2 requires the engine stay Studio-side.`,
      });
    }
  }

  // 3. Every checked-in preset CSS has the AUTOGENERATED header.
  const presetDir = path.join(REPO, 'content/themes');
  if (fs.existsSync(presetDir)) {
    const files = fs.readdirSync(presetDir).filter(f => f.endsWith('.css'));
    for (const f of files) {
      const head = readFile(`content/themes/${f}`).slice(0, 200);
      if (!/AUTOGENERATED by scripts\/render-presets\.mjs/.test(head)) {
        violations.push({
          assertion: 'preset:autogen-header',
          reason: `content/themes/${f} is missing the AUTOGENERATED header — hand-edited or stale. Run 'node scripts/render-presets.mjs'.`,
        });
      }
    }
    if (!files.length) {
      violations.push({
        assertion: 'preset:files-present',
        reason: `content/themes/ is empty — run 'node scripts/render-presets.mjs' to generate preset artifacts.`,
      });
    }
  }

  // 4. core/favicon/engine.js ICONS must match themes/engine.js FAVICON_ICONS.
  // Compare by extracting the `id:` values from each ICONS array — that's
  // the dimension most likely to drift (new icon added on one side only).
  try {
    const favRuntime = readFile('core/favicon/engine.js');
    const themeEngine = readFile('themes/engine.js');

    const idsFrom = (src, arrayName) => {
      const re = new RegExp(`(?:const\\s+)?${arrayName}\\s*=\\s*\\[(.*?)\\];`, 's');
      const m = src.match(re);
      if (!m) return null;
      return [...m[1].matchAll(/\bid:\s*'([a-z0-9_-]+)'/gi)].map(x => x[1]);
    };

    const runtimeIds = idsFrom(favRuntime, 'ICONS');
    const canonicalIds = idsFrom(themeEngine, 'FAVICON_ICONS');

    if (!runtimeIds) {
      violations.push({ assertion: 'favicon:ids-parse', reason: 'Could not parse ICONS from core/favicon/engine.js' });
    } else if (!canonicalIds) {
      violations.push({ assertion: 'favicon:ids-parse', reason: 'Could not parse FAVICON_ICONS from themes/engine.js' });
    } else {
      const a = runtimeIds.join(',');
      const b = canonicalIds.join(',');
      if (a !== b) {
        violations.push({
          assertion: 'favicon:ids-mirror',
          reason: `ICONS drifted between core/favicon/engine.js and themes/engine.js.\n  runtime:   ${a}\n  canonical: ${b}\nUpdate core/favicon/engine.js to match themes/engine.js.`,
        });
      }
    }
  } catch (err) {
    violations.push({ assertion: 'favicon:mirror-check', reason: `Favicon mirror check failed: ${err.message}` });
  }

  if (!violations.length) {
    console.log('✓ theme drift check passed');
    console.log('  manifest content_scripts: no theme engine files');
    console.log('  background.js: no inlined engine markers');
    console.log('  content/themes/*.css: all stamped AUTOGENERATED');
    console.log('  favicon ICONS: runtime mirror matches canonical engine');
    return 0;
  }

  console.error('✗ theme drift detected:');
  for (const v of violations) {
    console.error(`  [${v.assertion}] ${v.reason}`);
  }
  return 1;
}

process.exit(run());
